import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize and escape user input using OWASP Java Encoder library
        String sanitizedUserInput = Encode.forHtml(userInput);

        // Properly handle user input by encoding it into the HTML output
        String htmlOutput = "<html><body><h1>Welcome, " + sanitizedUserInput + "</h1></body></html>";

        // Output the HTML content to simulate rendering in a web page
        System.out.println(htmlOutput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
